SELECT soi.*,
u.user_avatar,
u.user_name,
u.user_account,
si.number AS seat_number,
c.id AS classroom_id,
c.cover AS classroom_cover,
c.name AS classroom_name
FROM seat_order_info soi
LEFT JOIN user u ON u.id = soi.user_id
LEFT JOIN seat_info si ON si.id = soi.seat_info_id
LEFT JOIN classroom c ON c.id = si.classroom_id


